#include <iostream>

using namespace std;

int main()
{
    for (int i = 1; i <= 10; i++)
    {
        if (i == 4)
        {
            break;
        }
        cout << i << endl;
    }

    return 0;
}

int numbers[] = {4, 8, 15, 16, 23, 42};
int target = 15;
bool found = false;

for (int i = 0; i < 6; i++)
{
    if (numbers[i] == target)
    {
        found = true;
        break; // no need to keep checking once it's found
    }
}

for (int i = 1; i <= 2; i++)
{
    for (int j = 1; j <= 3; j++)
    {
        if (j == 2)
        {
            break; // exits only the inner (j) loop
        }
        cout << i << j << " ";
    }
}

int i = 1;

while (true) // deliberately infinite
{
    if (i > 3)
    {
        break;
    }
    cout << i << endl;
    i++;
}

